let definitions: Record<string, ISchemaDTO> | undefined
const references = new Map<string, Schema>()

export const withSchemaDefinitions = <RESULT>(
  nextDefinitions: Record<string, ISchemaDTO> | undefined,
  callback: () => RESULT
): RESULT => {
  const previousDefinitions = definitions
  definitions = nextDefinitions
  references.clear()
  try {
    return callback()
  } finally {
    definitions = previousDefinitions
    references.clear()
  }
}

export const fromSchemaDTO = (schemaDTO: ISchemaDTO): Schema => {
  if ('$ref' in schemaDTO) {
    const definition = definitions?.[schemaDTO.$ref]
    if (definition === undefined) {
      throw new DynamoDBToolboxError('schema.dto.unknownRef', {
        message: `Unknown schema DTO reference '${schemaDTO.$ref}'.`,
        payload: { ref: schemaDTO.$ref }
      })
    }
    let reference = references.get(schemaDTO.$ref)
    if (reference === undefined) {
      reference = lazy(() => fromSchemaDTO(definition))
      references.set(schemaDTO.$ref, reference)
    }
    return reference
  }

  switch (schemaDTO.type) {
    case 'any':
      return fromAnySchemaDTO(schemaDTO)
    case 'null':
    case 'boolean':
    case 'number':
    case 'string':
    case 'binary':
      return fromPrimitiveSchemaDTO(schemaDTO)
    case 'set':
      return fromSetSchemaDTO(schemaDTO)
    case 'list':
      return fromListSchemaDTO(schemaDTO)
    case 'map':
      return fromMapSchemaDTO(schemaDTO)
    case 'record':
      return fromRecordSchemaDTO(schemaDTO)
    case 'anyOf':
      return fromAnyOfSchemaDTO(schemaDTO)
    case 'item':
      return fromItemSchemaDTO(schemaDTO)
  }
}
